SELECT ,

FROM t_user_health_goal ug
JOIN t_health_goal hg ON hg.goal_id = ug.goal_id
WHERE ug.user_goal_id = #{userGoalId}
  AND ug.user_id = #{userId}
LIMIT 1

SELECT ,

FROM t_user_health_goal ug
JOIN t_health_goal hg ON hg.goal_id = ug.goal_id
WHERE ug.user_id = #{userId}
  AND ug.goal_id = #{goalId}
LIMIT 1

SELECT ,
FROM t_user_health_goal ug JOIN t_health_goal hg ON hg.goal_id = ug.goal_id WHERE ug.user_id = #{userId}
AND ug.user_goal_status = #{userGoalStatus}
ORDER BY CASE WHEN ug.user_goal_status = 0 THEN 0 ELSE 1 END ASC, hg.sort_no ASC, ug.user_goal_id ASC

